// Inline definitions required for OpenCL compilation
// Avoiding #include "XSbench_header.h" because it contains C-specific headers (<chrono>, <stdio.h>) incompatible with OpenCL.

#define UNIONIZED 0
#define NUCLIDE 1
#define HASH 2
#define STARTING_SEED 1070

typedef struct{
    double energy;
    double total_xs;
    double elastic_xs;
    double absorbtion_xs;
    double fission_xs;
    double nu_fission_xs;
} NuclideGridPoint;

typedef struct{
    int nthreads;
    long n_isotopes;
    long n_gridpoints;
    int lookups;
    char * HM;
    int grid_type;
    int hash_bins;
    int particles;
    int simulation_method;
    int binary_mode;
    int kernel_id;
    int platform_id;
    int device_id;
} Inputs;

